from collections import deque
class PartialSumComputer:
    def __init__(self, length: int):
        self.length = length
        self.partial_sums = deque(maxlen=length)
    def update_partial_sum(self, new_value: int):
        new_value = abs(new_value)
        if len(self.partial_sums) < self.length:
            self.partial_sums.append(new_value)
        else:
            current_sum = sum(self.partial_sums)
            self.partial_sums.rotate(-1)
            self.partial_sums[-1] = new_value
    def get_partial_sum(self) -> int:
        return sum(self.partial_sums)
def f(numbers: list):
    transformed_numbers = [x if x % 2 == 0 else -(x ^ 1) for x in numbers]
    computer = PartialSumComputer(len(numbers) // 2 + 1)
    current_sum = 0
    for (i, num) in enumerate(transformed_numbers):
        new_value = num + i
        computer.update_partial_sum(new_value)
        current_sum += new_value
    return computer.get_partial_sum()

