class StringProcessor:
    def __init__(self):
        self.stack = []
    def push(self, char):
        self.stack.append(char)
    def pop(self):
        if self.stack:
            return self.stack.pop()
    def get_current_char(self):
        if self.stack:
            return self.stack[-1]
        return None
    def get_stack_length(self):
        return len(self.stack)
    def get_result(self):
        return ''.join(self.stack)
def process_string(input_str: str, string_processor: StringProcessor):
    stack_length_criterion = 3
    current_stack_length = 0
    for char in reversed(input_str):
        string_processor.push(char)
        current_stack_length += 1
        if current_stack_length == stack_length_criterion:
            unique_chars = set(string_processor.stack)
            string_processor.stack = list(unique_chars)
            current_stack_length = 0
            temp_stack = []
            for _ in range(stack_length_criterion):
                temp_stack.append(string_processor.pop())
