        return 0 <= x < self.size and 0 <= y < self.size and (self.maze[x][y] != '#')
    def solve(self):
        self.find_start_and_goal()
        stack = deque([(self.start, [])])
        while stack:
            ((current_x, current_y), path) = stack.pop()
            if (current_x, current_y) == self.goal:
                self.solution = path + [(current_x, current_y)]
